// WeakRef-based cache
class ResourceCache {
  #cache = new Map();
  #registry = new FinalizationRegistry((key) => {
    console.log(`Cache entry for '${key}' was GC'd — cleaning up`);
    this.#cache.delete(key); // Clean up Map entry
  });

  set(key, value) {
    const ref = new WeakRef(value);
    this.#cache.set(key, ref);
    this.#registry.register(value, key); // Notify when GC'd
  }

  get(key) {
    const ref = this.#cache.get(key);
    if (!ref) return undefined;
    const value = ref.deref(); // Could be undefined if GC'd
    if (!value) this.#cache.delete(key); // Cleanup stale Map entry
    return value;
  }
}

