// Retry with exponential backoff + jitter
async function withRetry(fn, { maxAttempts = 3, baseDelay = 1000, jitter = true } = {}) {
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (err) {
      if (attempt === maxAttempts) throw err;
      const delay = baseDelay * Math.pow(2, attempt - 1);
      const jitterDelay = jitter ? delay + Math.random() * delay * 0.2 : delay;
      await new Promise(r => setTimeout(r, jitterDelay));
    }
  }
}

// Circuit Breaker
class CircuitBreaker {
  #failures = 0;
  #state = 'closed'; // closed → open → half-open
  #nextRetry = 0;

  constructor(fn, { threshold = 5, timeout = 30000 } = {}) {
    this.fn = fn;
    this.threshold = threshold;
    this.timeout = timeout;
  }

  async call(...args) {
    if (this.#state === 'open') {
      if (Date.now() < this.#nextRetry) throw new Error('Circuit open');
      this.#state = 'half-open';
    }
    try {
      const result = await this.fn(...args);
      this.#failures = 0;
      this.#state = 'closed';
      return result;
    } catch (err) {
      this.#failures++;
      if (this.#failures >= this.threshold) {
        this.#state = 'open';
        this.#nextRetry = Date.now() + this.timeout;
      }
      throw err;
    }
  }
}

// Concurrency limiter (manual p-limit implementation)
function createConcurrencyLimiter(max) {
  let running = 0;
  const queue = [];
  return async (fn) => {
    if (running >= max) await new Promise(r => queue.push(r));
    running++;
    try { return await fn(); }
    finally { running--; queue.shift()?.(); }
  };
}

// Manual Observable implementation (simplified RxJS)
class Observable {
  constructor(subscribeFn) {
    this._subscribe = subscribeFn;
  }

  subscribe(observer) {
    return this._subscribe(observer);
  }

  map(fn) {
    return new Observable(observer =>
      this.subscribe({
        next: (val) => observer.next(fn(val)),
        error: (err) => observer.error(err),
        complete: () => observer.complete(),
      })
    );
  }

  filter(pred) {
    return new Observable(observer =>
      this.subscribe({
        next: (val) => pred(val) && observer.next(val),
        error: (err) => observer.error(err),
        complete: () => observer.complete(),
      })
    );
  }
}

