function runInWorker(type, payload) {
  return new Promise((resolve, reject) => {
    const handler = ({ data }) => {
      worker.removeEventListener('message', handler);
      resolve(data.result);
    };
    worker.addEventListener('message', handler);
    worker.addEventListener('error', reject, { once: true });
