// Method decorator — log execution time
function LogExecutionTime(target: any, key: string, descriptor: PropertyDescriptor) {
  const original = descriptor.value;
  descriptor.value = async function (...args: any[]) {
    const start = performance.now();
    const result = await original.apply(this, args);
    console.log(`${key} took ${performance.now() - start}ms`);
    return result;
  };
  return descriptor;
}

// Property decorator — validation via metadata
function IsEmail(target: any, propertyKey: string) {
  Reflect.defineMetadata('validation:type', 'email', target, propertyKey);
}

function validate(obj: any): string[] {
  const errors: string[] = [];
  for (const key of Object.keys(obj)) {
    const type = Reflect.getMetadata('validation:type', obj, key);
    if (type === 'email' && !obj[key].includes('@')) {
      errors.push(`${key} must be a valid email`);
    }
  }
  return errors;
}

