// Lazy image loading
const imageObserver = new IntersectionObserver(
  (entries) => {
    entries.forEach(entry => {
      if (!entry.isIntersecting) return;
      const img = entry.target;
      img.src = img.dataset.src; // Load real src
      img.classList.add('loaded');
      imageObserver.unobserve(img); // Stop watching once loaded
    });
  },
  {
    rootMargin: '200px 0px', // Start loading 200px before viewport
    threshold: 0             // Trigger as soon as 1px is visible
  }
);

document.querySelectorAll('img[data-src]').forEach(img => {
  imageObserver.observe(img);
});

// Infinite scroll — load more when sentinel enters view
const sentinel = document.getElementById('load-more-sentinel');
const scrollObserver = new IntersectionObserver(async ([entry]) => {
  if (!entry.isIntersecting) return;
  scrollObserver.unobserve(sentinel); // Pause while loading
  await loadNextPage();
  scrollObserver.observe(sentinel);   // Re-enable for next trigger
}, { threshold: 1.0 }); // Fully visible

scrollObserver.observe(sentinel);

// Analytics — track time element was visible
let visibleSince = null;
const analyticsObserver = new IntersectionObserver(([entry]) => {
  if (entry.isIntersecting) {
    visibleSince = performance.now();
  } else if (visibleSince) {
    const duration = performance.now() - visibleSince;
    trackEvent('content_viewed', { duration, id: entry.target.id });
    visibleSince = null;
  }
}, { threshold: 0.5 }); // 50% visible counts as 'seen'

// Watch for dynamically added elements
const observer = new MutationObserver((mutations) => {
  mutations.forEach(mutation => {
    mutation.addedNodes.forEach(node => {
      if (node.nodeType !== Node.ELEMENT_NODE) return;
      if (node.matches('.ad-banner')) {
        initAdTracking(node); // React to injected ads
      }
      // Also check subtree of added nodes
      node.querySelectorAll?.('.lazy-component').forEach(initLazy);
    });

    mutation.removedNodes.forEach(node => {
      if (node.nodeType === Node.ELEMENT_NODE) {
        cleanupComponent(node); // Cleanup removed elements
      }
    });
  });
});

observer.observe(document.body, {
  childList: true,  // Watch for added/removed children
  subtree: true,    // Watch all descendants, not just direct children
});

// Watch attribute changes
const attrObserver = new MutationObserver((mutations) => {
  mutations.forEach(({ attributeName, target, oldValue }) => {
    if (attributeName === 'aria-expanded') {
      handleAccordionToggle(target, oldValue);
    }
  });
});

attrObserver.observe(accordionEl, {
  attributes: true,
  attributeFilter: ['aria-expanded'], // Only watch specific attributes
  attributeOldValue: true
});

// Always disconnect when done
function cleanup() {
  observer.disconnect();
  attrObserver.disconnect();
}

// BAD: Different shapes — V8 creates multiple hidden classes
function makePoint(x, y, is3D) {
  const p = { x, y };
  if (is3D) p.z = 0; // Conditionally adds property — different shapes!
  return p;
}

// GOOD: Consistent shape — one hidden class, optimized
function makePoint(x, y, z = undefined) {
  return { x, y, z }; // Same structure always — V8 optimizes
}

// BAD: delete creates different hidden class
const obj = { a: 1, b: 2, c: 3 };
delete obj.b; // Shape change — V8 may deoptimize!
// GOOD: set to null/undefined instead:
obj.b = null;

// Monomorphic (optimized) vs Megamorphic (deoptimized)
function process(obj) {
  return obj.value * 2; // V8 learns the shape of obj
}
process({ value: 1 });         // shape A → V8 learns
process({ value: 2 });         // shape A → still optimized
process({ name: 'x', value: 3 }); // shape B → polymorphic, degrades perf

// Why this matters for benchmarks:
function benchmarkSort() {
  const arr = Array.from({ length: 10000 }, () => Math.random());

  // First few calls: Ignition (slow)
  // After enough calls: TurboFan optimizes to native code
  console.time('sort');
  arr.slice().sort((a, b) => a - b);
  console.timeEnd('sort');
}

// Warm up first in production benchmarks:
for (let i = 0; i < 100; i++) benchmarkSort(); // Allow JIT to kick in
benchmarkSort(); // This measurement is meaningful

